import json

rows = [json.loads(l) for l in open('/Users/margotiamanova/Desktop/REZOLVE AI/rail-arf-stt/tasks/t0014_granite_short_clip_robustness/data/short_clip_transcripts_whisper.jsonl')]
meta = {m['clip_id']: m for m in [json.loads(l) for l in open('/Users/margotiamanova/Desktop/REZOLVE AI/rail-arf-stt/tasks/t0014_granite_short_clip_robustness/data/short_clips_metadata.jsonl')]}

def word_overlap(a, b):
    wa = set(a.lower().split())
    wb = set(b.lower().split())
    if not wa or not wb:
        return 0.0
    return len(wa & wb) / min(len(wa), len(wb))

fixed = 0
for r in rows:
    ref = str(meta.get(r['clip_id'], {}).get('reference_text', '') or '')
    t = r['transcript'].strip()
    if t and not r['is_empty']:
        ov = word_overlap(t, ref)
        # hallucination: zero word overlap with non-empty reference, or empty reference
        if ov == 0.0:
            if not r['is_hallucination']:
                r['is_hallucination'] = True
                fixed += 1
                print(f\"FIXED {r['clip_id']} {r['duration_s']}s: '{t}' | ref: '{ref[:50]}'\")

print(f'Fixed: {fixed} clips')
"

